import { zodResolver } from '@hookform/resolvers/zod';import { useForm } from 'react-hook-form';import { Alert } from '@/components/ui/alert';import { Button } from '@/components/ui/button';import { supplierSchema } from '../schemas';import type { Supplier,SupplierCategory,SupplierFormValues } from '../types';
const fieldClass='mt-1 h-10 w-full rounded-lg border border-slate-300 bg-white px-3 text-sm text-slate-900 dark:border-slate-600 dark:bg-slate-800 dark:text-white';
export const SupplierForm=({supplier,categories,onSubmit,onCancel,isLoading,error}:{supplier?:Supplier|null;categories:SupplierCategory[];onSubmit:(v:SupplierFormValues)=>void;onCancel:()=>void;isLoading?:boolean;error?:string|null})=>{
 const {register,handleSubmit,watch,setValue,formState:{errors}}=useForm<SupplierFormValues>({resolver:zodResolver(supplierSchema),mode:'onTouched',defaultValues:supplier?{supplier_code:supplier.supplier_code,company_name:supplier.company_name,tax_number:supplier.tax_number??'',registration_number:supplier.registration_number??'',address:supplier.address??'',city:supplier.city??'',country:supplier.country??'',contact_person:supplier.contact_person??'',phone:supplier.phone??'',email:supplier.email??'',website:supplier.website??'',payment_terms:supplier.payment_terms??'',currency:supplier.currency,notes:supplier.notes??'',status:supplier.status==='archived'?'inactive':supplier.status,category_ids:supplier.categories?.map(x=>x.id)??[]}:{supplier_code:'',company_name:'',tax_number:'',registration_number:'',address:'',city:'',country:'Pakistan',contact_person:'',phone:'',email:'',website:'',payment_terms:'',currency:'PKR',notes:'',status:'active',category_ids:[]}});const selected=watch('category_ids');
 const input=(name:keyof SupplierFormValues,label:string,type='text')=><label className="block text-sm font-semibold text-slate-700 dark:text-slate-200">{label}<input type={type} {...register(name)} className={fieldClass}/>{errors[name]?<span className="mt-1 block text-xs text-red-600">{String(errors[name]?.message)}</span>:null}</label>;
 return <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">{error?<Alert variant="danger" title="Unable to save supplier">{error}</Alert>:null}<fieldset><legend className="mb-3 font-semibold text-slate-900 dark:text-white">Company information</legend><div className="grid gap-4 md:grid-cols-2">{input('supplier_code','Supplier Code')}{input('company_name','Company Name')}{input('tax_number','Tax Number')}{input('registration_number','Registration Number')}{input('website','Website','url')}<label className="block text-sm font-semibold text-slate-700 dark:text-slate-200">Status<select {...register('status')} className={fieldClass}><option value="active">Active</option><option value="inactive">Inactive</option><option value="on_hold">On hold</option></select></label></div></fieldset><fieldset><legend className="mb-3 font-semibold text-slate-900 dark:text-white">Address and terms</legend><div className="grid gap-4 md:grid-cols-2">{input('address','Address')}{input('city','City')}{input('country','Country')}{input('currency','Currency')}{input('payment_terms','Payment Terms')}</div></fieldset><fieldset><legend className="mb-3 font-semibold text-slate-900 dark:text-white">Primary contact</legend><div className="grid gap-4 md:grid-cols-2">{input('contact_person','Contact Person')}{input('phone','Phone','tel')}{input('email','Email','email')}</div></fieldset><fieldset><legend className="mb-3 font-semibold text-slate-900 dark:text-white">Supplier categories</legend><div className="grid gap-2 sm:grid-cols-2">{categories.map(c=><label key={c.id} className="flex items-center gap-2 rounded-lg border border-slate-200 p-3 text-sm dark:border-slate-700"><input type="checkbox" checked={selected.includes(c.id)} onChange={e=>setValue('category_ids',e.target.checked?[...selected,c.id]:selected.filter(id=>id!==c.id),{shouldDirty:true})}/><span>{c.name}</span></label>)}</div></fieldset><label className="block text-sm font-semibold text-slate-700 dark:text-slate-200">Notes<textarea {...register('notes')} rows={3} className={`${fieldClass} h-auto py-2`}/></label><div className="flex justify-end gap-2"><Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button><Button type="submit" isLoading={isLoading}>{supplier?'Save Changes':'Create Supplier'}</Button></div></form>;
};
